(function($){$.hash={process:(options,fn)=>{if(!$.isPlainObject(options))return console.error("`options` is not an object");else if(Object.keys(options).length===0)return;_urlHashActionHandler(options,fn)},add:(params,appendToUrl)=>_urlHashModificationHandler("add",params,appendToUrl),remove:params=>_urlHashModificationHandler("remove",params),removeAll:()=>_urlHashModificationHandler("removeAll",null),args:_getHashArgs};function _getHashArgs(){const hash=window.location.hash.trim().replaceAll("#","");if(hash==="")return;if(!_validUrlHash(hash))return;const args={};hash.split("&").forEach((pair=>{const keyValuePair=pair.split("=");args[keyValuePair[0]]=keyValuePair[1]}));return args}function _urlHashModificationHandler(action,params,appendToUrl=true){const hash=window.location.hash.replaceAll("#","");const urlSearchParams=new URLSearchParams(hash);if(action==="add"){if(!$.isPlainObject(params))return;for(const key in params){urlSearchParams.set(key,params[key])}}if(action==="remove"){if(typeof params==="string")urlSearchParams.delete(params);if($.isArray(params))params.forEach((p=>urlSearchParams.delete(p)))}if(action==="removeAll"&&hash){const hashKeys=hash.split("&").map((h=>h.split("=")[0]));hashKeys.forEach((p=>urlSearchParams.delete(p)))}const newHash=`#${urlSearchParams.toString()}`;if(appendToUrl)window.location.hash=newHash;return newHash}function _urlHashActionHandler(options,fn){const hash=window.location.hash.trim().replaceAll("#","");if(hash==="")return;if(!_validUrlHash(hash))return;const params=hash.split("&").map((pair=>{const keyValuePair=pair.split("=");return{[keyValuePair[0]]:keyValuePair[1]}}));if(fn&&typeof fn==="function")fn(params);params.forEach((p=>{const key=Object.keys(p)[0];const value=Object.values(p)[0];const callback=options[key];if(callback&&typeof callback==="function")callback(value)}))}function _validUrlHash(hash){const r=/^(?:[A-Za-z0-9-%20]+=[A-Za-z0-9-%20|.]+&?)+$/;return r.test(hash)}})(jQuery);